// RegisterArgoGoArgoMcpToolset registers the go-argo-mcp toolset with the runtime.
// The caller parameter provides the MCP client for making remote calls.
func RegisterArgoGoArgoMcpToolset(ctx context.Context, rt *agentsruntime.Runtime, caller mcpruntime.Caller) error {
	if rt == nil {
		return errors.New("runtime is required")
	}
	if caller == nil {
		return errors.New("mcp caller is required")
	}

	exec := func(ctx context.Context, call planner.ToolRequest) (planner.ToolResult, error) {
		fullName := call.Name
		toolName := string(fullName)
		const suitePrefix = "argo.go-argo-mcp."
		if strings.HasPrefix(toolName, suitePrefix) {
			toolName = toolName[len(suitePrefix):]
		}
		payload, err := json.Marshal(call.Payload)
		if err != nil {
			return planner.ToolResult{Name: fullName}, err
		}
		resp, err := caller.CallTool(ctx, mcpruntime.CallRequest{
			Payload: payload,
			Suite:   "argo.go-argo-mcp",
			Tool:    toolName,
		})
		if err != nil {
			return ArgoGoArgoMcpToolsetHandleError(fullName, err), nil
		}
		var value any
		if len(resp.Result) > 0 {
			if err := json.Unmarshal(resp.Result, &value); err != nil {
				return planner.ToolResult{Name: fullName}, err
			}
		}
		var toolTelemetry *telemetry.ToolTelemetry
		if len(resp.Structured) > 0 {
			var structured any
			if err := json.Unmarshal(resp.Structured, &structured); err != nil {
				return planner.ToolResult{Name: fullName}, err
			}
			toolTelemetry = &telemetry.ToolTelemetry{Extra: map[string]any{"structured": structured}}
		}
		return planner.ToolResult{
			Name:      fullName,
			Result:    value,
			Telemetry: toolTelemetry,
		}, nil
	}

	return rt.RegisterToolset(agentsruntime.ToolsetRegistration{
		DecodeInExecutor: true,
		Description:      "MCP service for Argo Workflows operations.",
		Execute: func(ctx context.Context, call *planner.ToolRequest) (*agentsruntime.ToolExecutionResult, error) {
			if call == nil {
				return nil, errors.New("tool request is nil")
			}
			out, err := exec(ctx, *call)
			if err != nil {
				return nil, err
			}
			return agentsruntime.Executed(&out), nil
		},
		Name:  "argo.go-argo-mcp",
		Specs: ArgoGoArgoMcpToolsetToolSpecs,
	})
}

// ArgoGoArgoMcpToolsetHandleError converts an error into a tool result with appropriate retry hints.
func ArgoGoArgoMcpToolsetHandleError(toolName tools.Ident, err error) planner.ToolResult {
	result := planner.ToolResult{
		Error: planner.ToolErrorFromError(err),
		Name:  toolName,
	}
	if hint := ArgoGoArgoMcpToolsetRetryHint(toolName, err); hint != nil {
		result.RetryHint = hint
	}
	return result
}

// ArgoGoArgoMcpToolsetRetryHint determines if an error should trigger a retry and returns appropriate hints.
func ArgoGoArgoMcpToolsetRetryHint(toolName tools.Ident, err error) *planner.RetryHint {
	key := string(toolName)
	var retryErr *retry.RetryableError
	if errors.As(err, &retryErr) {
		return &planner.RetryHint{
			Message:        retryErr.Prompt,
			Reason:         planner.RetryReasonInvalidArguments,
			RestrictToTool: true,
			Tool:           toolName,
		}
	}
	var rpcErr *jsonrpc.Error
	if errors.As(err, &rpcErr) {
		switch rpcErr.Code {
		case jsonrpc.CodeInvalidParams:
			var schemaJSON string
			var example string
			switch key {
			case "list_workflows":
				schemaJSON = "{\"type\":\"object\",\"properties\":{\"limit\":{\"type\":\"integer\",\"description\":\"Maximum number of workflows to return\",\"default\":50,\"minimum\":1},\"namespace\":{\"type\":\"string\",\"description\":\"Kubernetes namespace to query\"},\"status\":{\"type\":\"string\",\"description\":\"Optional workflow status filter\",\"enum\":[\"Running\",\"Succeeded\",\"Failed\",\"Pending\",\"Error\"]}},\"additionalProperties\":false}"
				example = "{\"limit\":0}"
			case "get_workflow":
				schemaJSON = "{\"type\":\"object\",\"required\":[\"name\"],\"properties\":{\"name\":{\"type\":\"string\"},\"namespace\":{\"type\":\"string\"}},\"additionalProperties\":false}"
				example = "{\"name\":\"example\"}"
			case "get_workflow_logs":
				schemaJSON = "{\"type\":\"object\",\"required\":[\"workflow_name\"],\"properties\":{\"container\":{\"type\":\"string\",\"default\":\"main\"},\"max_lines\":{\"type\":\"integer\",\"description\":\"Maximum lines to return; zero returns all lines\",\"default\":200,\"minimum\":0},\"namespace\":{\"type\":\"string\"},\"pod_name\":{\"type\":\"string\"},\"search\":{\"type\":\"string\"},\"workflow_name\":{\"type\":\"string\"}},\"additionalProperties\":false}"
				example = "{\"container\":\"example\",\"max_lines\":0,\"workflow_name\":\"example\"}"
			case "terminate_workflow":
				schemaJSON = "{\"type\":\"object\",\"required\":[\"name\",\"reason\"],\"properties\":{\"confirmation_token\":{\"type\":\"string\"},\"dry_run\":{\"type\":\"boolean\",\"description\":\"Preview mode; defaults to true\"},\"name\":{\"type\":\"string\"},\"namespace\":{\"type\":\"string\"},\"reason\":{\"type\":\"string\"}},\"additionalProperties\":false}"
				example = "{\"name\":\"example\",\"reason\":\"example\"}"
			case "retry_workflow":
				schemaJSON = "{\"type\":\"object\",\"required\":[\"name\"],\"properties\":{\"name\":{\"type\":\"string\"},\"namespace\":{\"type\":\"string\"},\"restart_successful\":{\"type\":\"boolean\",\"description\":\"Also restart successful steps; defaults to false\"}},\"additionalProperties\":false}"
				example = "{\"name\":\"example\"}"
			case "list_cron_workflows":
				schemaJSON = "{\"type\":\"object\",\"properties\":{\"namespace\":{\"type\":\"string\"},\"suspended\":{\"type\":\"boolean\"}},\"additionalProperties\":false}"
				example = "{}"
			case "get_cron_workflow":
				schemaJSON = "{\"type\":\"object\",\"required\":[\"name\"],\"properties\":{\"name\":{\"type\":\"string\"},\"namespace\":{\"type\":\"string\"}},\"additionalProperties\":false}"
				example = "{\"name\":\"example\"}"
			case "get_cron_history":
				schemaJSON = "{\"type\":\"object\",\"required\":[\"name\"],\"properties\":{\"limit\":{\"type\":\"integer\",\"default\":10,\"minimum\":1},\"name\":{\"type\":\"string\"},\"namespace\":{\"type\":\"string\"}},\"additionalProperties\":false}"
				example = "{\"limit\":0,\"name\":\"example\"}"
			case "toggle_cron_suspension":
				schemaJSON = "{\"type\":\"object\",\"required\":[\"name\",\"suspend\"],\"properties\":{\"name\":{\"type\":\"string\"},\"namespace\":{\"type\":\"string\"},\"suspend\":{\"type\":\"boolean\"}},\"additionalProperties\":false}"
				example = "{\"name\":\"example\",\"suspend\":false}"
			case "list_workflow_templates":
				schemaJSON = "{\"type\":\"object\",\"properties\":{\"label_selector\":{\"type\":\"string\"},\"namespace\":{\"type\":\"string\"}},\"additionalProperties\":false}"
				example = "{}"
			case "get_workflow_template":
				schemaJSON = "{\"type\":\"object\",\"required\":[\"name\"],\"properties\":{\"name\":{\"type\":\"string\"},\"namespace\":{\"type\":\"string\"}},\"additionalProperties\":false}"
				example = "{\"name\":\"example\"}"
			case "list_cluster_workflow_templates":
				schemaJSON = "{\"type\":\"object\",\"properties\":{\"label_selector\":{\"type\":\"string\"}},\"additionalProperties\":false}"
				example = "{}"
			case "get_cluster_workflow_template":
				schemaJSON = "{\"type\":\"object\",\"required\":[\"name\"],\"properties\":{\"name\":{\"type\":\"string\"}},\"additionalProperties\":false}"
				example = "{\"name\":\"example\"}"
			}
			prompt := retry.BuildRepairPrompt("tools/call:"+key, rpcErr.Message, example, schemaJSON)
			return &planner.RetryHint{
				Message:        prompt,
				Reason:         planner.RetryReasonInvalidArguments,
				RestrictToTool: true,
				Tool:           toolName,
			}
		case jsonrpc.CodeMethodNotFound:
			return &planner.RetryHint{
				Message: rpcErr.Message,
				Reason:  planner.RetryReasonToolUnavailable,
				Tool:    toolName,
			}
		}
	}
	return nil
}
